// HasEventBooking applies the HasEdge predicate on the "event_booking" edge.
func HasEventBooking() predicate.MealEntitlement {
	return predicate.MealEntitlement(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, EventBookingTable, EventBookingColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEventBookingWith applies the HasEdge predicate on the "event_booking" edge with a given conditions (other predicates).
func HasEventBookingWith(preds ...predicate.EventBooking) predicate.MealEntitlement {
	return predicate.MealEntitlement(func(s *sql.Selector) {
		step := newEventBookingStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.MealEntitlement) predicate.MealEntitlement {
	return predicate.MealEntitlement(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.MealEntitlement) predicate.MealEntitlement {
	return predicate.MealEntitlement(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.MealEntitlement) predicate.MealEntitlement {
	return predicate.MealEntitlement(sql.NotPredicates(p))
}
